'use client';

import { motion, type Variants } from 'framer-motion';
import { ArrowRight, Bot, Check, Cpu, Gauge, ShieldCheck, Sparkles, Workflow } from 'lucide-react';
import { useState, type ComponentType, type ReactNode, useEffect, useRef } from 'react';
import IngenifyLogo from '@/components/IngenifyLogo';
import RequestAccessForm from '@/components/RequestAccessForm';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import QuantumBackground from '@/components/QuantumBackground';

interface FeatureCard {
  title: string;
  description: string;
  icon: ComponentType<{ className?: string }>;
  className: string;
}


const reveal: Variants = {
  hidden: {
    opacity: 0,
    y: 40,
    filter: 'blur(12px)',
  },
  show: {
    opacity: 1,
    y: 0,
    filter: 'blur(0px)',
    transition: {
      duration: 1,
      ease: [0.16, 1, 0.3, 1],
    },
  },
};

const trustedBy = [
  'TechCore Systems',
  'Velocity Digital',
  'Guardian Security',
  'Apex Platforms',
  'Nexus Innovation',
  'Sentinel Labs',
];

const features: FeatureCard[] = [
  {
    title: 'Architectural Excellence',
    description:
      'Full-stack mastery with modern architectures (Next.js, TypeScript, Distributed Databases). Component-driven design, real-time data synchronization, and cloud-native deployments built for scalability and modularity.',
    icon: Cpu,
    className: 'lg:col-span-2',
  },
  {
    title: 'Core Web Vitals',
    description: 'Server-side rendering and optimized LCP for lightning-fast performance at scale.',
    icon: Gauge,
    className: 'lg:col-span-1',
  },
  {
    title: 'SEO at the Foundation',
    description: 'Automated schema markup and semantic HTML structures engineered for visibility.',
    icon: Sparkles,
    className: 'lg:col-span-1',
  },
  {
    title: 'Security-by-Design',
    description: 'End-to-end encryption, JWT/OAuth2 authentication, and CSRF/XSS mitigation at every layer.',
    icon: ShieldCheck,
    className: 'lg:col-span-1',
  },
  {
    title: 'The Fortress Standard',
    description: 'Proactive vulnerability patching and rigorous compliance standards protecting business logic and user data.',
    icon: Workflow,
    className: 'lg:col-span-2',
  },
];


function SectionReveal({
  children,
  className = '',
  id,
}: {
  children: ReactNode;
  className?: string;
  id?: string;
}) {
  return (
    <motion.section
      id={id}
      initial="hidden"
      whileInView="show"
      viewport={{ once: true, amount: 0.2 }}
      variants={reveal}
      className={className}
    >
      {children}
    </motion.section>
  );
}

export default function IngenifyLanding() {
  const heroLogoRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!heroLogoRef.current) return;
    const { clientX, clientY } = e;
    const { innerWidth, innerHeight } = window;
    
    // Calculate mouse position relative to center [-1 to 1]
    const x = (clientX / innerWidth - 0.5) * 2;
    const y = (clientY / innerHeight - 0.5) * 2;
    
    gsap.to(heroLogoRef.current, {
      rotateY: x * 25,
      rotateX: -y * 25,
      x: x * -30,
      y: y * -30,
      duration: 1.5,
      ease: 'power3.out',
    });
  };

  const handleMouseLeave = () => {
    if (!heroLogoRef.current) return;
    gsap.to(heroLogoRef.current, {
      rotateY: 0,
      rotateX: 0,
      x: 0,
      y: 0,
      duration: 2.5,
      ease: 'elastic.out(1, 0.3)',
    });
  };

  useEffect(() => {
    gsap.registerPlugin(ScrollTrigger);

    if (heroLogoRef.current) {
      gsap.to(heroLogoRef.current, {
        rotateZ: 45,
        rotateX: 15,
        scale: 0.7,
        y: 100,
        opacity: 0.8,
        ease: 'power2.inOut',
        scrollTrigger: {
          trigger: '#hero',
          start: 'top top',
          end: 'bottom top',
          scrub: true,
        },
      });
    }
  }, []);

  return (
    <div 
      ref={containerRef} 
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      className="infinity-theme relative min-h-screen overflow-x-clip text-slate-100 [perspective:2000px]"
    >
      <QuantumBackground />

      <header className="fixed inset-x-0 top-0 z-50 border-b border-white/5 bg-black/20 backdrop-blur-3xl">
        <nav className="mx-auto flex w-full max-w-6xl items-center justify-between px-6 py-4">
          <a href="#hero" className="shrink-0">
            <IngenifyLogo />
          </a>
          <div className="hidden items-center gap-8 text-sm font-medium text-slate-300 md:flex uppercase tracking-widest">
            <a href="#features" className="transition hover:text-white">
              Features
            </a>
            <a href="#lead-capture" className="transition hover:text-white">
              Request Access
            </a>
          </div>
          <a
            href="#lead-capture"
            className="inline-flex items-center gap-2 rounded-full border border-white/20 bg-white px-5 py-2.5 text-sm font-semibold text-black transition hover:bg-slate-200"
          >
            Get Started
            <ArrowRight className="h-4 w-4" />
          </a>
        </nav>
      </header>

      <main className="mx-auto w-full max-w-6xl px-6 pb-20 pt-32 sm:pt-48">
        <SectionReveal id="hero" className="scroll-mt-28 flex flex-col items-center text-center">
          <div className="mb-16 flex justify-center [transform-style:preserve-3d]">
            <div 
              ref={heroLogoRef} 
              className="relative mix-blend-screen"
            >
              <div className="absolute inset-0 bg-gradient-to-tr from-cyan-400 to-indigo-600 blur-[80px] opacity-40 scale-150 animate-pulse" />
              
              {/* Holographic Aberration Layers */}
              <div className="absolute inset-0 translate-x-1 translate-y-1 opacity-70 drop-shadow-[0_0_15px_rgba(255,0,0,0.8)] filter hue-rotate-[120deg]">
                <IngenifyLogo size={240} compact />
              </div>
              <div className="absolute inset-0 -translate-x-1 -translate-y-1 opacity-70 drop-shadow-[0_0_15px_rgba(0,255,255,0.8)] filter hue-rotate-[-120deg]">
                <IngenifyLogo size={240} compact />
              </div>
              
              {/* Core Layer */}
              <div className="relative z-10 drop-shadow-[0_0_30px_rgba(255,255,255,0.4)]">
                <IngenifyLogo size={240} compact />
              </div>
            </div>
          </div>
          <div className="max-w-4xl">
            <p className="inf-mono inline-flex items-center gap-2 rounded-full border border-white/10 bg-white/5 px-4 py-2 text-[10px] uppercase tracking-[0.3em] text-slate-400 font-bold">
              <Sparkles className="h-3 w-3" />
              Elite Engineering Partnership
            </p>
            <h1 className="inf-heading mt-8 text-5xl leading-[1.1] text-white sm:text-7xl">
              Secure, Visible, and Scalable Digital Ecosystems
            </h1>
            <p className="mx-auto mt-8 max-w-2xl text-base leading-relaxed text-slate-300 sm:text-lg">
              Ingenify bridges creative vision and technical fortitude. We engineer high-performance platforms with architectural excellence, SEO at the foundation, and security by design.
            </p>
            <div className="mt-12 flex flex-wrap justify-center gap-4">
              <a
                href="#lead-capture"
                className="inline-flex items-center gap-2 rounded-full bg-white px-8 py-4 text-sm font-bold text-black transition hover:bg-slate-200 shadow-2xl shadow-white/10"
              >
                Request Access
                <ArrowRight className="h-4 w-4" />
              </a>
              <a
                href="#features"
                className="inf-mono inline-flex items-center gap-2 rounded-full border border-white/20 px-8 py-4 text-xs font-bold text-white transition hover:bg-white hover:text-black uppercase tracking-widest"
              >
                Technical Spec
              </a>
            </div>
          </div>
        </SectionReveal>

        <SectionReveal id="features" className="scroll-mt-24 py-32 border-t border-white/10">
          <div className="mb-16 max-w-2xl">
            <p className="inf-mono text-[10px] uppercase tracking-[0.4em] text-slate-400 font-bold mb-4">/ Pillars</p>
            <h2 className="inf-heading text-4xl text-white sm:text-5xl">The Technical Standard</h2>
            <p className="mt-4 text-slate-300">
              Architectural excellence, visibility by design, and fortress-standard security in every solution.
            </p>
          </div>

          <div className="grid gap-6 lg:grid-cols-3">
            {features.map((feature) => {
              const Icon = feature.icon;
              return (
                <motion.article
                  key={feature.title}
                  whileHover={{ y: -5 }}
                  transition={{ type: 'spring', stiffness: 300, damping: 20 }}
                  className={`glass-card glow-border rounded-2xl p-8 hover:border-indigo-400/50 hover:shadow-[0_0_20px_rgba(99,102,241,0.2)] transition-all ${feature.className}`}
                >
                  <div className="mb-6 inline-flex rounded-xl border border-indigo-300/35 bg-indigo-500/15 p-4 text-indigo-100">
                    <Icon className="h-6 w-6" />
                  </div>
                  <h3 className="inf-heading text-lg text-white mb-3">{feature.title}</h3>
                  <p className="text-sm leading-relaxed text-slate-300">{feature.description}</p>
                </motion.article>
              );
            })}
          </div>
        </SectionReveal>

      </main>

      <SectionReveal id="lead-capture" className="scroll-mt-24 border-t border-white/10 bg-black/40 backdrop-blur-3xl py-24">
        <div className="mx-auto grid w-full max-w-6xl gap-16 px-6 lg:grid-cols-[1.1fr_1fr]">
          <div className="space-y-8">
            <p className="inf-mono inline-flex items-center gap-2 rounded-full border border-indigo-400/35 bg-indigo-500/10 px-4 py-2 text-[10px] uppercase tracking-[0.2em] text-indigo-100 font-bold">
              <Sparkles className="h-3.5 w-3.5" />
              The Ingenify Promise
            </p>
            <h2 className="inf-heading text-4xl text-white sm:text-5xl leading-tight">Web Solutions as Secure and Visible</h2>
            <p className="max-w-xl text-lg text-slate-300 leading-relaxed">
              Let's discuss how Ingenify can engineer high-performance, scalable digital ecosystems. We manage the complexity of the modern web so you can focus on the ingenuity of your business.
            </p>
          </div>

          <div className="glass-card glow-border rounded-2xl p-8 sm:p-10">
            <RequestAccessForm />
          </div>
        </div>
      </SectionReveal>

      <footer className="border-t border-white/10 py-12">
        <div className="mx-auto flex w-full max-w-6xl flex-wrap items-center justify-between gap-6 px-6 text-xs text-slate-400 font-bold uppercase tracking-widest">
          <IngenifyLogo compact className="opacity-80" />
          <p>© {new Date().getFullYear()} Ingenify / Technical Standards</p>
        </div>
      </footer>
    </div>
  );
}
